//! Michelson serialization

use crate::{ast::Value, lexer::Prim};

/// Helper type with common encoding operations.
pub struct Buf(Vec<u8>);

impl Buf {
    /// Create a buffer and write given bytes to it.
    pub fn start_with(v: Vec<u8>) -> Self {
        Buf(v)
    }

    /// Obtain the result.
    pub fn finalize(self) -> Vec<u8> {
        self.0
    }

    /// Put one byte.
    pub fn byte(&mut self, b: u8) {
        self.0.push(b)
    }

    /// Put a Michiline primitive.
    pub fn prim(&mut self, prim: Prim, args_num: u8) {
        self.byte(args_num * 2 + 3);
        self.byte(prim as u8)
    }

    /// Put length of something.
    pub fn put_len(&mut self, len: u32) {
        self.0.extend_from_slice(&len.to_be_bytes())
    }

    /// Put dynamically-sized bytes.
    pub fn dynamic_bytes(&mut self, bs: &[u8]) {
        self.byte(0x0a);
        self.put_len(bs.len() as u32);
        self.0.extend_from_slice(bs)
    }

    /// Put a Michelson string.
    pub fn string(&mut self, s: &str) {
        self.byte(0x01);
        self.put_len(s.len() as u32);
        self.0.extend_from_slice(s.as_bytes())
    }

    /// Put a container.
    pub fn list<V>(&mut self, list: &[V], encoder: impl Fn(&mut Buf, &V)) {
        self.byte(0x02);
        self.put_len(0); // don't know the right length in advance
        let i = self.0.len();
        for val in list {
            encoder(self, val)
        }
        let written_len = (self.0.len() - i) as u32;
        self.0[(i - 4)..i].copy_from_slice(&written_len.to_be_bytes())
    }
}

impl Value {
    /// Serialize value using Michelson encoding.
    fn encode(&self) -> Vec<u8> {
        self.encode_starting_with(&[])
    }

    /// Like [Value::encode], but allows specifying a prefix, useful for
    /// `PACK` implementation.
    fn encode_starting_with(&self, start_bytes: &[u8]) -> Vec<u8> {
        let mut buf = Buf::start_with(Vec::from(start_bytes));
        encode_value(&mut buf, self);
        buf.finalize()
    }
}

/// Recursive encoding function for [Value].
fn encode_value(buf: &mut Buf, value: &Value) {
    use Value::*;
    match value {
        Number(_) => todo!(), // for a later MR
        Boolean(false) => buf.prim(Prim::False, 0),
        Boolean(true) => buf.prim(Prim::True, 0),
        Unit => buf.prim(Prim::Unit, 0),
        String(s) => buf.string(s),
        Bytes(b) => buf.dynamic_bytes(b),
        Pair(p) => {
            buf.prim(Prim::Pair, 2);
            encode_value(buf, &p.0);
            encode_value(buf, &p.1);
        }
        Option(None) => {
            buf.prim(Prim::None, 0);
        }
        Option(Some(v)) => {
            buf.prim(Prim::Some, 1);
            encode_value(buf, v);
        }
        Seq(l) => buf.list(l, encode_value),
        Elt(e) => {
            buf.prim(Prim::Elt, 2);
            encode_value(buf, &e.0);
            encode_value(buf, &e.1);
        }
    }
}

#[cfg(test)]
mod test_encoding {
    use super::*;

    mod value {
        #[track_caller]
        fn check(v: impl Into<Value>, hex_bytes: &str) {
            let hex_bytes: &str = match hex_bytes.strip_prefix("0x") {
                Some(s) => s,
                None => hex_bytes,
            };
            assert_eq!(v.into().encode(), hex::decode(hex_bytes).unwrap())
        }

        // To figure out the expected bytes, use
        // octez-client convert data 'VALUE' from michelson to binary

        use crate::ast::Elt;

        use super::*;

        #[test]
        fn primitive_values() {
            check((), "0x030b");
            check(true, "0x030a");
            check(false, "0x0303");
        }

        #[test]
        fn simple_nested() {
            check((true, ""), "0x0707030a0100000000");
            check(None::<()>, "0x0306");
            check(Some(()), "0x0509030b");
            check(Elt(true, ()), "0x0704030a030b");
        }

        #[test]
        fn string() {
            check("", "0x0100000000");
            check("abc", "0x0100000003616263");
            check(
                "123456789123456789123456789",
                "0x010000001b313233343536373839313233343536373839313233343536373839",
            );
        }

        #[test]
        fn very_long_string() {
            // Using "\"$(printf 'x%.0s' {1..1000})\"" as a value
            // Verifies that length is encoded as a fixed-length number, not as zarith
            check(
                ['x'].iter().cycle().take(1000).collect::<String>(),
               ""
            );
        }

        #[test]
        fn bytes() {
            check(hex::decode("").unwrap(), "0x0a00000000");
            check(hex::decode("001234abff").unwrap(), "0x0a00000005001234abff");
        }

        #[test]
        fn list() {
            check(Vec::<()>::new(), "0x0200000000");
            check(vec![true, false], "0x0200000004030a0303");
        }

        #[test]
        fn deeply_nested_list() {
            check(
                vec![vec![], vec![true]],
                "0x020000000c02000000000200000002030a",
            );
        }

        #[test]
        fn very_long_list() {
            // Using "{ $(printf 'Unit;%.0s' {1..1000}) }" as a value
            // Verifies that length is encoded as a fixed-length number, not as zarith
            check(
                vec![(); 1000],
                "",
          );
        }
    }
}
